#!/usr/bin/env bash
set -euo pipefail

bundle_root="$(cd "$(dirname "${BASH_SOURCE[0]}")/../.." && pwd)"
command=$(cat <<'__CODEx_HOOK_COMMAND__'
bash -c 'input=$(cat); COMMAND=$(echo "$input" | jq -r ".tool_input.command // empty"); SUCCESS=$(echo "$input" | jq -r ".tool_response.success // false"); if [[ "$COMMAND" =~ (vercel|deploy|build) ]] && [ -n "$VERCEL_TOKEN" ] && [ -n "$VERCEL_PROJECT_ID" ]; then echo "рџЏҐ Deployment Health Monitor: Checking deployment status..."; DEPLOY_DATA=$(curl -s -H "Authorization: Bearer $VERCEL_TOKEN" "https://api.vercel.com/v6/deployments?projectId=$VERCEL_PROJECT_ID&limit=5" 2>/dev/null); if [ -n "$DEPLOY_DATA" ] && [ "$DEPLOY_DATA" != "null" ]; then RECENT_DEPLOYMENTS=$(echo "$DEPLOY_DATA" | jq -r ".deployments[]"); TOTAL_DEPLOYMENTS=$(echo "$DEPLOY_DATA" | jq ".deployments | length"); SUCCESS_COUNT=0; ERROR_COUNT=0; BUILDING_COUNT=0; echo "рџ“Љ Recent deployment analysis ($TOTAL_DEPLOYMENTS deployments):"; echo "$DEPLOY_DATA" | jq -r ".deployments[] | \"State: \(.state) | Created: \(.created | todateiso8601) | URL: \(.url // \"N/A\")\""; for state in $(echo "$DEPLOY_DATA" | jq -r ".deployments[].state"); do case "$state" in READY) ((SUCCESS_COUNT++));; ERROR|CANCELED) ((ERROR_COUNT++));; BUILDING|QUEUED) ((BUILDING_COUNT++));; esac; done; SUCCESS_RATE=$(( SUCCESS_COUNT * 100 / TOTAL_DEPLOYMENTS )); echo "" ; echo "рџ“€ Deployment Health Summary:"; echo "вњ… Successful: $SUCCESS_COUNT/$TOTAL_DEPLOYMENTS ($SUCCESS_RATE%)"; echo "вќЊ Failed: $ERROR_COUNT/$TOTAL_DEPLOYMENTS"; echo "рџ”„ In Progress: $BUILDING_COUNT/$TOTAL_DEPLOYMENTS"; if [ $ERROR_COUNT -gt 0 ]; then echo "" >&2; echo "рџљЁ DEPLOYMENT HEALTH ALERT!" >&2; echo "Recent failures detected: $ERROR_COUNT failed deployments" >&2; echo "Success rate: $SUCCESS_RATE%" >&2; echo "" >&2; echo "рџ”Ќ Failed deployments:" >&2; echo "$DEPLOY_DATA" | jq -r ".deployments[] | select(.state == \"ERROR\" or .state == \"CANCELED\") | \"вќЊ \(.created | todateiso8601): \(.url // \"No URL\")\"" >&2; echo "" >&2; echo "рџ’Ў Troubleshooting steps:" >&2; echo "вЂў Check Vercel dashboard for detailed error logs" >&2; echo "вЂў Review recent code changes" >&2; echo "вЂў Verify environment variables are set" >&2; echo "вЂў Check for build script errors" >&2; if [ $SUCCESS_RATE -lt 50 ]; then echo "рџљЁ CRITICAL: Success rate below 50%!" >&2; exit 2; fi; elif [ $SUCCESS_RATE -lt 80 ]; then echo "вљ пёЏ Warning: Success rate below 80%"; fi; if [ $BUILDING_COUNT -gt 2 ]; then echo "вЏі Multiple builds in progress ($BUILDING_COUNT)"; echo "рџ’Ў This might indicate build queue issues"; fi; LATEST_DEPLOY=$(echo "$DEPLOY_DATA" | jq -r ".deployments[0]"); LATEST_STATE=$(echo "$LATEST_DEPLOY" | jq -r ".state"); LATEST_URL=$(echo "$LATEST_DEPLOY" | jq -r ".url // empty"); LATEST_CREATED=$(echo "$LATEST_DEPLOY" | jq -r ".created"); if [ -n "$LATEST_CREATED" ] && [ "$LATEST_CREATED" != "null" ]; then MINUTES_AGO=$(( ($(date +%s) - $LATEST_CREATED/1000) / 60 )); echo "рџ•’ Latest deployment: $LATEST_STATE ($MINUTES_AGO minutes ago)"; if [ -n "$LATEST_URL" ]; then echo "рџЊђ URL: https://$LATEST_URL"; fi; fi; echo "вњ… Deployment health check completed"; else echo "вќЊ Unable to fetch deployment data from Vercel API"; fi; else echo "в„№пёЏ Deployment health monitoring skipped (not a deployment command or missing tokens)"; fi'
__CODEx_HOOK_COMMAND__
)

cd "$bundle_root"
exec "$bundle_root/.codex/hooks/_shared/run-with-hook-env.sh" -- bash -lc "$command"
